[Serializable]
public class Permission
{
    public string Name { get; set; }
    public string Resource { get; set; }
    public List<string> AllowedActions { get; set; }
    public DateTime GrantedAt { get; set; }
    public DateTime? ExpiresAt { get; set; }

    public Permission()
    {
        AllowedActions = new List<string>();
        GrantedAt = DateTime.UtcNow;
    }

    public Permission(string name, string resource, params string[] actions) : this()
    {
        Name = name;
        Resource = resource;
        AllowedActions.AddRange(actions);
    }

    public bool IsExpired()
    {
        return ExpiresAt.HasValue && DateTime.UtcNow > ExpiresAt.Value;
    }

    public bool CanPerform(string action)
    {
        if (IsExpired()) return false;
        return AllowedActions.Contains(action) || AllowedActions.Contains("*");
    }

    public void AddAction(string action)
    {
        if (!AllowedActions.Contains(action))
            AllowedActions.Add(action);
    }

    public void RevokeAction(string action)
    {
        AllowedActions.Remove(action);
    }

    public override string ToString()
    {
        return $"Permission({Name}, Resource={Resource}, Actions=[{string.Join(", ", AllowedActions)}], Expired={IsExpired()})";
    }
}

[Serializable]
public class CartItem
{
    public string ProductId { get; set; }
    public string ProductName { get; set; }
    public decimal Price { get; set; }
    public int Quantity { get; set; }

    public CartItem() { }

    public CartItem(string productId, string productName, decimal price, int quantity = 1)
    {
        ProductId = productId;
        ProductName = productName;
        Price = price;
        Quantity = quantity;
    }

    public decimal GetSubtotal()
    {
