public class Program
{
    public static void Main(string[] args)
    {
        Console.WriteLine("=== Session Management System Demo ===\n");

        string sessionDir = Path.Combine(Path.GetTempPath(), "demo_sessions_" + Guid.NewGuid().ToString("N").Substring(0, 8));
        var manager = new SessionManager(sessionDir);

        try
        {
            // Create a session
            Console.WriteLine("--- Creating Session ---");
            var session = manager.CreateSession("user-001", "john_doe", "john@example.com", TimeSpan.FromHours(2));
            Console.WriteLine($"Session created: {session}\n");

            // Configure preferences
            Console.WriteLine("--- Setting Preferences ---");
            session.Preferences.Theme = "dark";
            session.Preferences.Language = "en-US";
            session.Preferences.Currency = "USD";
            session.Preferences.ItemsPerPage = 50;
            session.Preferences.SetCustomSetting("sidebar_collapsed", "false");
            session.Preferences.SetCustomSetting("default_view", "grid");
            Console.WriteLine($"Theme: {session.Preferences.Theme}");
            Console.WriteLine($"Language: {session.Preferences.Language}");
            Console.WriteLine($"Items per page: {session.Preferences.ItemsPerPage}");
            Console.WriteLine($"Custom setting 'default_view': {session.Preferences.GetCustomSetting("default_view")}\n");

            // Add shopping cart items
            Console.WriteLine("--- Adding Cart Items ---");
            session.Cart.AddItem(new CartItem("PROD-001", "Wireless Mouse", 29.99m, 1));
            session.Cart.AddItem(new CartItem("PROD-002", "Mechanical Keyboard", 89.99m, 1));
            session.Cart.AddItem(new CartItem("PROD-003", "USB-C Hub", 45.50m, 2));
            session.Cart.AddItem(new CartItem("PROD-001", "Wireless Mouse", 29.99m, 1)); // Add another mouse

            Console.WriteLine("Cart contents:");
            foreach (var item in session.Cart.Items)
                Console.WriteLine($"  {item}");
            Console.WriteLine($"Cart total: {session.Cart.GetTotal():C}");
            Console.WriteLine($"Total items: {session.Cart.GetItemCount()}\n");

            // Add permissions
            Console.WriteLine("--- Adding Permissions ---");
            session.AddPermission(new Permission("admin_dashboard", "/admin", "read", "write"));
            session.AddPermission(new Permission("user_management", "/admin/users", "read", "create", "update", "delete"));
            session.AddPermission(new Permission("reports", "/reports", "read", "export"));

            var tempPermission = new Permission("temp_access", "/beta-features", "read")
            {
                ExpiresAt = DateTime.UtcNow.AddMinutes(30)
            };
            session.AddPermission(tempPermission);

            Console.WriteLine("Permissions:");
            foreach (var perm in session.Permissions)
                Console.WriteLine($"  {perm}");

            Console.WriteLine($"\nCan access /admin with 'read'? {session.HasPermission("/admin", "read")}");
            Console.WriteLine($"Can access /admin with 'delete'? {session.HasPermission("/admin", "delete")}");
            Console.WriteLine($"Can access /admin/users with 'delete'? {session.HasPermission("/admin/users", "delete")}");
            Console.WriteLine($"Active permissions: {session.GetActivePermissions().Count}\n");

            // Add metadata
            session.Metadata["ip_address"] = "192.168.1.100";
            session.Metadata["user_agent"] = "Mozilla/5.0";
            session.Metadata["login_method"] = "password";

            // Save session to disk
            Console.WriteLine("--- Saving Session to Disk ---");
            manager.SaveSession(session);
            string savedSessionId = session.SessionId;
            Console.WriteLine();

            // Print stats
            manager.PrintSessionStats();
            Console.WriteLine();

            // Load session from disk (simulating a new request)
            Console.WriteLine("--- Loading Session from Disk ---");
            var loadedSession = manager.LoadSession(savedSessionId);
            if (loadedSession != null)
            {
                Console.WriteLine($"Loaded session: {loadedSession}");
                Console.WriteLine($"User: {loadedSession.Username} ({loadedSession.Email})");
                Console.WriteLine($"Theme: {loadedSession.Preferences.Theme}");
                Console.WriteLine($"Cart items: {loadedSession.Cart.GetItemCount()}, Total: {loadedSession.Cart.GetTotal():C}");
                Console.WriteLine($"Permissions: {loadedSession.Permissions.Count}");
                Console.WriteLine($"Has admin read? {loadedSession.HasPermission("/admin", "read")}");
                Console.WriteLine($"IP: {loadedSession.Metadata["ip_address"]}");
            }
            Console.WriteLine();

            // Update cart after loading
            Console.WriteLine("--- Updating Cart ---");
            loadedSession.Cart.UpdateQuantity("PROD-003", 3);
            loadedSession.Cart.RemoveItem("PROD-002");
            Console.WriteLine("Updated cart:");
            foreach (var item in loadedSession.Cart.Items)
                Console.WriteLine($"  {item}");
            Console.WriteLine($"New total: {loadedSession.Cart.GetTotal():C}\n");

            // Save updated session
            manager.SaveSession(loadedSession);

            // Create additional sessions
            Console.WriteLine("--- Creating Additional Sessions ---");
            var session2 = manager.CreateSession("user-002", "jane_smith", "jane@example.com");
            session2.Cart.AddItem(new CartItem("PROD-005", "Monitor Stand", 79.99m, 1));
            session2.AddPermission(new Permission("basic_access", "/dashboard", "read"));
            manager.SaveSession(session2);

            var session3 = manager.CreateSession("user-003", "bob_wilson", "bob@example.com");
            session3.Preferences.Theme = "blue";
            session3.Preferences.Language = "fr";
            manager.SaveSession(session3);
            Console.WriteLine();

            // Print final stats
            manager.PrintSessionStats();
            Console.WriteLine();

            // Demonstrate permission revocation
            Console.WriteLine("--- Permission Management ---");
            Console.WriteLine($"Before revocation - user management permission exists: {loadedSession.HasPermission("/admin/users", "delete")}");
            loadedSession.RemovePermission("user_management");
            Console.WriteLine($"After revocation - user management permission exists: {loadedSession.HasPermission("/admin/users", "delete")}");
            Console.WriteLine();

            // Demonstrate session destruction
            Console.WriteLine("--- Destroying a Session ---");
            manager.DestroySession(session3.SessionId);
            Console.WriteLine($"Active sessions after destroy: {manager.GetActiveSessionCount()}\n");

            // Cleanup
            Console.WriteLine("--- Cleanup ---");
            manager.CleanupExpiredSessions();
            manager.PrintSessionStats();

            Console.WriteLine("\n=== Demo Complete ===");
        }
        finally
        {
            // Clean up demo directory
            try
            {
                if (Directory.Exists(sessionDir))
                    Directory.Delete(sessionDir, true);
                Console.WriteLine($"\nCleaned up temporary session directory: {sessionDir}");
            }
            catch { }
        }
    }
}